Okey, its alive! There is only thing it still cant do, to make more complex joins, like this Table1->Table2->Table3. But joins like Table1->Table2 its easy and in any count! 
```SQL
JOIN TABLE2
  ON TABLE2.ID = TABLE1.field
JOIN TABLE3
  ON TABLE3.ID = TABLE1.field
```
And the most beautiful part of it, it only depends on your model and schema, you only "hardcode" names of fields.
Example how it works
```python
class EmployesModel(Base):
  ID = Column(Integer, primary_key=True)
  name = Column(String)


class MyModel(Base):
  ID = Column(Integer, primary_key=True)
  test = Column(String)
  employee_id = Column(Integer, ForeignKey('EmployesModel.ID')
  employee_id_connection = relationship(EmployesModel)

class MyModel(SQLAlchemyObjectType):
    class Meta:
        model = MyModel
        interfaces = (relay.Node,)

class MyModelInputSchema(InputObjectType):
    name = String()


class MyModelQuery(ObjectType):
    test = relay.Node.Field(MyModel)
    all_tests = CustomConnectionField(MyModel, employee_id_connection=MyModelInputSchema())
```
and query: 
```graphql
query {
  allTests(employeeIdConnection:{name:"test"}){
     test
     employeeIdConnection{
        name
     }
  }
}
```
here code of CustomConnection
```python
@classmethod
    def get_query(cls, model, info, **args):
        query = super(CustomConnectionField, cls).get_query(model, info, **args)
        for field, value in args.items():
            if field not in cls.RELAY_ARGS:
                for arg in cls.CUSTOM_ARGS:
                    if arg in field:
                        query = query.filter(
                            getattr(model, field.replace('_' + arg, '')).like('%{}%'.format(value))
                        )
                        return query
                    if isinstance(value, InputObjectType):
                        values = list(value.values())
                        keys = list(value.keys())
                        rel = inspect(model).relationships[field]
                        if len(values) > 1 or len(keys) > 1:
                            for key, val in value.items():
                                query = query.join(
                                    rel.mapper.class_,
                                    getattr(model, field.replace('_' + arg, ''))
                                ).filter(
                                    getattr(rel.mapper.class_, key) == val
                                )
                        else:
                            query = query.join(
                                rel.mapper.class_,
                                getattr(model, field.replace('_' + arg, ''))
                            ).filter(
                                getattr(rel.mapper.class_, keys[0]) == values[0]
                            )
                    else:
                        query = query.filter(
                            getattr(model, field) == value
                        )
        return query
```

